const body = $json.body || $json || {};
const ticketId = body.ticket_id || body.id;
const traceId = body.trace_id || `ctk-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
const runId = $execution?.id ? String($execution.id) : `manual-${Date.now()}`;
if (!ticketId) {
  return [{ json: { route: 'error', stage: 'validate_inbound', error: 'missing_ticket_id', trace_id: traceId, run_id: runId, raw: body } }];
}
return [{ json: { route: 'ok', stage: 'validate_inbound', trace_id: traceId, run_id: runId, ticket_id: String(ticketId), inbound_priority: body.priority || 'critical' } }];

const ctx = $node['Store Inbound Context'].json;
const detail = $json || {};
if (detail.error || detail.statusCode >= 400) {
  return [{ json: { route: 'error', stage: 'fetch_ticket', trace_id: ctx.trace_id, run_id: ctx.run_id, error: detail.error || 'ticket_fetch_failed', status: detail.statusCode, ticket_id: ctx.ticket_id } }];
}
return [{ json: { route: 'ok', stage: 'merge_enriched', trace_id: ctx.trace_id, run_id: ctx.run_id, ticket_id: ctx.ticket_id, title: detail.title || 'Critical Ticket', description: detail.description || detail.summary || 'No details provided.', priority: detail.priority || ctx.inbound_priority || 'critical', status: detail.status || 'open', assignee: detail.assignee || 'Unassigned', reporter: detail.reporter || 'N/A', created_at: detail.created_at || new Date().toISOString(), ticket_url: (($env.FRONTEND_BASE_URL || 'http://localhost:3000') + '/tickets/' + ctx.ticket_id) } }];

const d = $json;
const priority = String(d.priority || 'critical').toUpperCase();
const subject = `[ITSM][CRITICAL] ${priority} - ${d.ticket_id} - ${d.title || 'Critical Ticket'}`;
const description = d.description || d.summary || d.body || 'No details provided.';
const body = `Critical ticket ${d.ticket_id || 'N/A'} requires immediate attention. The ticket titled "${d.title || 'N/A'}" is currently in status "${d.status || 'open'}" with priority "${priority}", assigned to ${d.assignee || 'Unassigned'} and reported by ${d.reporter || 'N/A'}. Description summary: ${description}. The ticket was created at ${d.created_at || new Date().toISOString()} and can be opened here: ${d.ticket_url || 'N/A'}. Trace reference: ${d.trace_id || 'N/A'}; workflow run: ${d.run_id || 'N/A'}. Source: system:n8n.`;
return [{ json: { ...d, stage: 'build_email', email_subject: subject, email_body: body } }];

const payload = {
  workflow: 'Critical Ticket Detector',
  channel: 'teams',
  timestamp: new Date().toISOString(),
  route: $json.error ? 'error' : 'ok',
  status: $json.statusCode || null,
  error: $json.error || null,
  response: $json.body || $json.data || null,
};
if (payload.route === 'error') {
  console.error('[n8n][critical-ticket-detector][teams]', JSON.stringify(payload));
} else {
  console.log('[n8n][critical-ticket-detector][teams]', JSON.stringify(payload));
}
return [{ json: payload }];

const payload = {
  workflow: 'Critical Ticket Detector',
  timestamp: new Date().toISOString(),
  stage: $json.stage || 'unknown',
  route: 'error',
  trace_id: $json.trace_id || 'N/A',
  run_id: $json.run_id || 'N/A',
  ticket_id: $json.ticket_id || 'N/A',
  error: $json.error || $json.message || JSON.stringify($json)
};
console.error('[n8n][critical-ticket-detector][error]', JSON.stringify(payload));
return [{ json: payload }];

const payload = {
  workflow: 'Critical Ticket Detector',
  timestamp: new Date().toISOString(),
  stage: 'email_sent',
  route: 'ok',
  trace_id: $json.trace_id || 'N/A',
  run_id: $json.run_id || 'N/A',
  ticket_id: $json.ticket_id || 'N/A',
  email_to: ($env.CRITICAL_ALERT_EMAIL_TO || $env.ALERT_DEFAULT_EMAIL || $env.SLA_ALERT_EMAIL_TO || 'N/A'),
  message_id: $json.messageId || null
};
console.log('[n8n][critical-ticket-detector][success]', JSON.stringify(payload));
return [{ json: payload }];
